var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아이 씨……. 역시 내가 너무 심하게 말했나…….","JPN":"むう……やっぱり言いすぎたかな……","ENG":"Argh… Was I out of line back there?","TWN":"可惡……我說得太過火了嗎……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"민우 아저씨 생각에는 어때요? 그 정상 참참인가 안 돼요?","JPN":"マツダおじさんはどう思います？　その、じょーじょーしゃくりょなんちゃらっていうものはダメ？","ENG":"What do you think, Mr. Minwoo? You think this counts as an extenuary circumcision?","TWN":"民宇叔叔，你覺得呢？這樣不算情無可原嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……엠마를 돌볼 사람 필요하다고 따라온 거 아니었나?","JPN":"……エマにはお世話をする人が必要と言って付いてきたんじゃなかったか？","ENG":"Didn't you tag along because Emma needs a caretaker?","TWN":"……你不是來照顧愛瑪的嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아까부터 자기 고민 상담만 신나게 하는 것 같다만.","JPN":"さっきから自分の悩み相談で盛り上がっているようだが。","ENG":"It feels more like you're here to vent.","TWN":"但你從剛才就一直在說自己的事。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"치. 엠마가 눈 하나 깜빡하는 것까지 계속 보고 있걸랑요.","JPN":"ちっ、エマの瞬きも見逃さずにずっと見ていますよ？","ENG":"Hmph. I've been watching Emma's every move. Including how many times she blinks.","TWN":"拜託，我有顧著好嗎！連愛瑪有沒有眨個眼睛我都一直盯著。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"정확히는 정상 참작이고, 이런 경우에 쓸 말도 아냐.","JPN":"まず、正しくは情状酌量だ。そしてこういう場合に使う言葉ではない。","ENG":"Anyway, it's called \\"extenuating circumstances,\\" and that's not how you're supposed to use it.","TWN":"正確的說法是情有可原，你的情況也不適用情有可原這句話。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자기가 언니라고 하더니 결국 대판 싸워 버렸군. 어른이고 싶다면 먼저 사과해.","JPN":"自分のことをいつもお姉ちゃんだとか言っておいて大げんかしたんだな。大人になりたければ先に謝ればいい。","ENG":"You were acting like you're the grownup only to end up fighting, huh. You should apologize first if you want to be a real grownup.","TWN":"你自己說你是姊姊，卻又跟人家鬧翻。想成為大人的話，就先道歉。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"제가 왜요. 억지는 맨날 걔가 부리는데.","JPN":"なんでアタシが？　あり得ないことを言ってるのはあの子ですよ？","ENG":"Why should I? She's the one who's being ridiculous all the time.","TWN":"憑什麼？！是她一直要跟我吵欸！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"나는 호라이즌이다~ 젖병 물고 다닐 것처럼 생겼지만 무시무시한 사채업자다~ 으에~","JPN":"アタシはホライズンだぁー見た目は哺乳瓶を持っててもおかしくないガキだけど、実は恐ろしい闇金業者だぞぉーがおぉー","ENG":"Boo, I'm Horizon! I look like a total baby but I'm actually a scary loan shark! Boo!","TWN":"我是地平線～雖然外表看起來像還在喝奶的年紀，但其實是凶狠的高利貸～矮額～"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"언니……. 유치해…….","JPN":"お姉ちゃん……子どもみたい……","ENG":"Rachel… You're so immature…","TWN":"姊姊……你好幼稚……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"흥. 넌 퇴원하면 웃다가 울 때까지 간지럼 형벌인 줄 알아.","JPN":"ふん、あんたには退院したら笑い過ぎて涙が出てくるまでくすぐられる刑が待っているんだからね。","ENG":"Hmph. Once you get all better, I'm going to tickle you to death.","TWN":"哼！等你出院後，罰你搔癢搔到哭出來為止！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……어쩌면 사실일지도 모르지.","JPN":"……もしかしたら事実かもしれないしな。","ENG":"…She might be telling the truth.","TWN":"……或許，她說的是真的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네? 그 사채업자 타령이요?","JPN":"え？　闇金業者が？","ENG":"What? You mean all that gibberish about being a loan shark?","TWN":"什麼真的？高利貸喔？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"걔한테 뒷돈이라도 받았어요? 뜬금없이 무슨 소리에요?","JPN":"急にどうしたんですか？　あの子からお金でももらいました？","ENG":"Did she bribe you or something? Where's this even coming from?","TWN":"你是不是有收她的錢？突然胡說八道什麼？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러는 너는 호라이즌 파이낸스에 대해 얼마나 알지?","JPN":"そんなあんたはホライズン・ファイナンスについてどの程度知っているんだ？","ENG":"Well, exactly how much do you know about Horizon Finance?","TWN":"那你對地平線金融了解多少？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐……. 갱단들도 설설 기던 사채업자라는 것만요.","JPN":"まあ……ギャングでさえ恐れていた闇金業者ってことぐらいは。","ENG":"Well… All I know is that even the gangs were scared of them.","TWN":"嗯…就…是連幫派都不敢得罪的高利貸。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어른들한테 들었어요. 호라이즌 파이낸스가 있을 때는 갱단들도 사람들이랑 눈도 못 마주쳤다고요.","JPN":"大人たちから聞きました。ホライズン・ファイナンスがいた当時は、ギャングも住民に下手な真似ができなかったって。","ENG":"I heard the grownups talk about it. The gangs didn't dare mess with anyone when Horizon Finance was around.","TWN":"我聽大人們說的，說地平線金融還在的時候，那些幫派連和人對到眼都不敢。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};